#include <iostream>
#include <cassert>
using namespace std;

int sumNumbers(int num1, int num2);
int sumNumbers(int num1, int num2, int num3);

int main() {
    assert(sumNumbers(5, 3, 2) == 10);
    assert(sumNumbers(10, -2, 5) == 13);
    assert(sumNumbers(-5, -3, -2) == -10);
    assert(sumNumbers(0, 7, 3) == 10);
    assert(sumNumbers(100, 200, 50) == 350);
    cout << "All tests passed!" << endl;
    return 0;
}
